function addTip(out: string[], seen: Set<string>, tip: string): void {
  const clean = tip.replace(/\s+/g, ' ').trim();
  if (!clean || seen.has(clean)) return;
  seen.add(clean);
  out.push(clean);
}

function sentence(text: string): string {
  const clean = text.trim();
  return clean ? clean[0].toUpperCase() + clean.slice(1) : clean;
}

function addCurated(out: string[], seen: Set<string>): void {
  for (const tip of CURATED_TIPS) addTip(out, seen, tip);
}

function addMonsterTips(out: string[], seen: Set<string>): void {
  for (const m of MONSTER_TIPS) {
    addTip(out, seen, `${m.name}: ${m.cue}. ${sentence(m.tactic)}.`);
    addTip(out, seen, `${m.name}: ${m.mistake}. ${sentence(m.tactic)}.`);
    addTip(out, seen, `${m.name}: ${m.loot}.`);
    addTip(out, seen, `${m.name}: ${sentence(m.cue)}. Сначала проверьте отход, потом лут.`);
  }
}

function addToolTips(out: string[], seen: Set<string>, tools: readonly ToolTip[]): void {
  for (const tool of tools) {
    addTip(out, seen, `${tool.name}: ${tool.use}.`);
    addTip(out, seen, `${tool.name}: ${tool.warning}.`);
    addTip(out, seen, `${tool.name}: ${tool.stock}.`);
    addTip(out, seen, `${tool.name}: сначала проверьте задачу, запас и путь отхода.`);
  }
}

function addPlaceTips(out: string[], seen: Set<string>): void {
  for (const place of PLACE_TIPS) {
    addTip(out, seen, `${place.name}: ${place.danger}. ${sentence(place.prep)}.`);
    addTip(out, seen, `${place.name}: ${place.habit}.`);
    addTip(out, seen, `${place.name}: перед лутом проверьте дверь, шум и обратный путь.`);
    addTip(out, seen, `${place.name}: если началась сирена, спор с местом заканчивается бегом к герме.`);
  }
}

function addItemTips(out: string[], seen: Set<string>): void {
  for (const item of ITEM_TIPS) {
    addTip(out, seen, `${item.name}: ${item.use}.`);
    addTip(out, seen, `${item.name}: ${item.warning}.`);
    addTip(out, seen, `${item.name}: ${item.trade}.`);
  }
}

function addStaticTips(out: string[], seen: Set<string>, tips: readonly string[]): void {
  for (const tip of tips) addTip(out, seen, tip);
}

function addCrossTips(out: string[], seen: Set<string>): void {
  let i = 0;
  while (out.length < TARGET_TIP_COUNT && i < 4000) {
    const monster = MONSTER_TIPS[i % MONSTER_TIPS.length];
    const weapon = WEAPON_TIPS[(i * 7) % WEAPON_TIPS.length];
    const place = PLACE_TIPS[(i * 11) % PLACE_TIPS.length];
    const item = ITEM_TIPS[(i * 13) % ITEM_TIPS.length];
    const psi = PSI_TIPS[(i * 17) % PSI_TIPS.length];
    const variant = i % 6;

    if (variant === 0) {
      addTip(out, seen, `${place.name}: если там встречается ${monster.name.toLowerCase()}, ${monster.tactic}.`);
    } else if (variant === 1) {
      addTip(out, seen, `${weapon.name} против ${monster.name.toLowerCase()}: ${weapon.warning}; ${monster.mistake}.`);
    } else if (variant === 2) {
      addTip(out, seen, `${item.name} в рейде: ${item.use}; перед ${place.name.toLowerCase()} проверьте, нужен ли слот под добычу.`);
    } else if (variant === 3) {
      addTip(out, seen, `${psi.name} и ${monster.name.toLowerCase()}: ${psi.use}; после применения держите дверь или угол.`);
    } else if (variant === 4) {
      addTip(out, seen, `${place.name} и ${weapon.name.toLowerCase()}: ${weapon.stock}; ${place.habit}.`);
    } else {
      addTip(out, seen, `${monster.name}: ${monster.cue}. Если рядом ${place.name.toLowerCase()}, не начинайте с ящика.`);
    }

    i++;
  }
}

function buildTips(): string[] {
  const out: string[] = [];
  const seen = new Set<string>();
  addCurated(out, seen);
  addMonsterTips(out, seen);
  addToolTips(out, seen, WEAPON_TIPS);
  addToolTips(out, seen, PSI_TIPS);
  addPlaceTips(out, seen);
  addItemTips(out, seen);
  addStaticTips(out, seen, FACTION_TIPS);
  addStaticTips(out, seen, ROUTE_TIPS);
  addCrossTips(out, seen);

  if (out.length < TARGET_TIP_COUNT) {
    throw new Error(`tips pool is too small: ${out.length}/${TARGET_TIP_COUNT}`);
  }

  return out.slice(0, TARGET_TIP_COUNT);
}

const TIPS: string[] = buildTips();

export const TIP_COUNT = TIPS.length;

/** Случайный совет с номером: «Совет 7: ...» */
export function randomTip(): string {
  const i = Math.floor(Math.random() * TIPS.length);
  return `Совет ${i + 1}: ${TIPS[i]}`;
}
